#include "markforge/logging.h"
static const char*level_color(mf_log_level_t l){ switch(l){case MF_LOG_TRACE:return "\033[90m";case MF_LOG_DEBUG:return "\033[36m";case MF_LOG_INFO:return "\033[32m";case MF_LOG_WARN:return "\033[33m";case MF_LOG_ERROR:return "\033[31m";case MF_LOG_FATAL:return "\033[35m";default:return "";} }
const char*mf_log_level_name(mf_log_level_t level){ switch(level){case MF_LOG_TRACE:return "TRACE";case MF_LOG_DEBUG:return "DEBUG";case MF_LOG_INFO:return "INFO";case MF_LOG_WARN:return "WARN";case MF_LOG_ERROR:return "ERROR";case MF_LOG_FATAL:return "FATAL";default:return "LOG";} }
void mf_log_init(mf_logger_t*logger){ if(logger){logger->file=NULL;logger->console_enabled=1;logger->color_enabled=1;logger->min_level=MF_LOG_INFO;} }
mf_result_t mf_log_set_file(mf_logger_t*logger,const char*path){ if(!logger||!path) return MF_ERROR_INVALID; logger->file=fopen(path,"ab"); return logger->file?MF_OK:MF_ERROR_IO; }
void mf_log_close(mf_logger_t*logger){ if(logger&&logger->file){fclose(logger->file);logger->file=NULL;} }
static void emit(FILE*out,int color,mf_log_level_t level,const char*stamp,const char*file,const char*func,int line,const char*msg){ if(color) fprintf(out,"%s",level_color(level)); fprintf(out,"%s [%s] %s:%s:%d: %s",stamp,mf_log_level_name(level),file,func,line,msg); if(color) fprintf(out,"\033[0m"); fprintf(out,"\n"); }
void mf_log_write(mf_logger_t*logger,mf_log_level_t level,const char*file,const char*func,int line,const char*fmt,...){ char msg[2048]; char stamp[64]; time_t t; struct tm *tmv; va_list ap; mf_logger_t def; if(!logger){mf_log_init(&def);logger=&def;} if(level<logger->min_level) return; va_start(ap,fmt); vsnprintf(msg,sizeof(msg),fmt,ap); va_end(ap); t=time(NULL); tmv=localtime(&t); if(tmv) strftime(stamp,sizeof(stamp),"%Y-%m-%d %H:%M:%S",tmv); else strcpy(stamp,"0000-00-00 00:00:00"); if(logger->console_enabled) emit(stderr,logger->color_enabled,level,stamp,file,func,line,msg); if(logger->file) emit(logger->file,0,level,stamp,file,func,line,msg); }
